     * Security: Only free buffer if we allocated it in this function.
     * Set to NULL immediately after freeing to prevent double-free.
     * On success, caller is responsible for freeing ctx->temp_buffer.
     */
    if (ret != 0) {
        if (buffer_allocated_here && ctx->temp_buffer != NULL) {
            free(ctx->temp_buffer);
            ctx->temp_buffer = NULL;  /* Prevent double-free */
            ctx->buffer_size = 0;
        }
    }

    return ret;
}
